--事件触发配置

EventTriggerConfig = {}
EventTriggerConfig.Event = {}

function EventTriggerConfig:init(configs)
    for _, config in pairs(configs) do
        local item = {}
        item.id = tonumber(config.id)
        item.attackTime = tonumber(config.attackTime)
        item.eventId = config.eventId
        item.times = tonumber(config.times)
        self.Event[item.id] = item
    end
end

function EventTriggerConfig:getEventByEventIdAndTimes(eventId, times)
    for _, event in pairs(self.Event) do
        if event.eventId == eventId and event.times == times then
            return event
        end
    end
end

return EventTriggerConfig
